#include <stdio.h>
#include <stdlib.h>

int main() {
  int *arr = (int*)calloc(5, sizeof(int));
  for (int i = 0; i < 5; i++) {
    printf("%d ", arr[i]);
  }
  printf("\n");
  arr = (int*)realloc(arr, 8 * sizeof(int));
  for (int i = 5; i < 8; i++) {
    arr[i] = i * 10;
  }
  for (int i = 0; i < 8; i++) {
    printf("%d ", arr[i]);
  }
  printf("\n");
  free(arr);
  return 0;
}
